#include "test.h"
#include "feature/speed.c"

#define EPS (1e-4)

/* Test support function */
static int almost_equal(float a, float b)
{
    float diff = a > b ? a - b : b - a;
    return diff < EPS;
}

static int compare_floats(const void *a, const void *b) {
    float fa = *(const float*) a;
    float fb = *(const float*) b;
    return (fa > fb) - (fa < fb);
}

static char *test_est_params_13x9() {
    float sample_pic[9 * 13] = {
        7.86, 4.69, 0.91, -1.37, 0.49, 7.36, 3.0, -3.17, -0.6, -0.78, 0.51, 4.93, 0.15,
        2.43, -0.7, 1.08, -1.0, -1.25, 1.79, -0.3, 2.89, 0.74, -1.69, -1.35, 0.72, -1.65,
        -2.23, -3.72, -0.05, -2.41, -4.17, 0.99, 3.82, 3.13, -2.06, 0.54, 2.9, -0.92, -1.53,
        -1.84, 1.57, 3.06, -0.91, -1.19, -0.89, -1.25, -1.14, -2.92, 2.29, 6.61, 0.36, -0.11,
        -1.45, 1.21, 2.0, 1.67, -0.31, -1.87, -2.68, -0.12, -3.34, -2.65, 0.81, -0.32, -0.97,
        0.74, -0.44, -2.7, 4.63, 3.01, 0.78, -1.91, -0.95, -0.89, -0.09, -1.58, 0.78, 1.47,
        2.14, 3.92, -4.08, -4.39, -1.2, 1.87, -1.09, -1.09, 0.52, 1.31, -2.23, -1.49, 0.32,
        -3.84, 2.4, 2.1, -2.95, -4.24, 1.5, 0.28, 1.27, 2.29, 1.91, -2.4, -1.36, -1.64,
        2.37, 1.27, 1.86, 7.02, 1.78, -0.72, -2.33, -2.79, -2.4, 0.12, -0.74, 1.12, 0.74,
    };

    float independent_term[9 * 12];
    float linear_system_sol[9 * 12];
    float cov_mat[9 * 9];
    float eigenvalues[9];
    float tmp_buffer[5 * 9 * 9 + 2 * 9 * 12];
    float ref_entropies[3 * 4];
    float ref_variances[3 * 4];
    float dis_entropies[3 * 4];
    float dis_variances[3 * 4];

    SpeedResultBuffers ref_results = {
        .entropies = ref_entropies,
        .variances = ref_variances,
    };
    SpeedResultBuffers dis_results = {
        .entropies = dis_entropies,
        .variances = dis_variances,
    };
    SpeedBuffers buffers = {
        .independent_term = independent_term,
        .linear_system_sol = linear_system_sol,
        .cov_mat = cov_mat,
        .eigenvalues = eigenvalues,
        .tmp_buffer = tmp_buffer,
    };

    SpeedDimensions dimensions = {
        .operating_width = 13,
        .operating_height = 9,
        .block_size = 3,
        .truncated_width = 12,
        .truncated_height = 9,
        .num_blocks_horizontal = 4,
        .num_blocks_vertical = 3,
        .num_blocks = 12,
        .elements_in_block = 9,
        .submatrix_width = 10,
        .submatrix_height = 7,
    };

    SpeedState speed_state = {
        .dimensions = dimensions,
        .ref_results = ref_results,
        .dis_results = dis_results,
        .buffers = buffers,
        .float_stride = 13 * sizeof(float),
    };

    float expected_entropy[] = {
        62.61018648, 63.12108021, 65.8986951,  55.66976117,
        47.21675636, 50.25993884, 59.12113044, 58.38842338,
        62.19691515, 61.1713589,  51.08823474, 45.50999794,
    };

    float expected_variance[] = {
        1.6228419,  1.68918131, 2.09931166, 0.93845804,
        0.47526583, 0.60855795, 1.23333762, 1.16401841,
        1.57105656, 1.4494503,  0.65059199, 0.41313011,
    };

    est_params(&speed_state, sample_pic, 0.1, &ref_results);

    for (size_t i = 0; i < dimensions.num_blocks_vertical; i++) {
        for (size_t j = 0; j < dimensions.num_blocks_horizontal; j++) {
            mu_assert("entropy incorrect", almost_equal(ref_results.entropies[i * dimensions.num_blocks_horizontal + j], expected_entropy[i * dimensions.num_blocks_horizontal + j]));
        }
    }

    for (size_t i = 0; i < dimensions.num_blocks_vertical; i++) {
        for (size_t j = 0; j < dimensions.num_blocks_horizontal; j++) {
            mu_assert("variance incorrect", almost_equal(ref_results.variances[i * dimensions.num_blocks_horizontal + j], expected_variance[i * dimensions.num_blocks_horizontal + j]));
        }
    }

    return NULL;
}

