static char *test_get_eigenvalues_5x5() {
    int size = 5;

    float data[] = {
        -6.35, 4.03, 0.32, 0.71, 7.46,
        4.03, 4.81, 0.83, -4.55, -0.5,
        0.32, 0.83, 3.88, -0.5, 1.8,
        0.71, -4.55, -0.5, 3.36, 6.28,
        7.46, -0.5, 1.8, 6.28, -2.14,
    };
    float tmp_buffer[5 * 5 * 5];

    float eigenvalues[5];
    compute_eigenvalues(data, eigenvalues, size, tmp_buffer);

    float expected_eigenvalues[] = {
        -13.129728,
        -4.471946,
        3.282901,
        7.276687,
        10.602085,
    };

    qsort(eigenvalues, size, sizeof(float), compare_floats);
    for (int i = 0; i < size; i++) {
        mu_assert("test_get_eigenvalues: eigenvalue is not close", almost_equal(eigenvalues[i], expected_eigenvalues[i]));
    }
    return NULL;
}

